// ============================================================
// NODE: Validate & Prepare Booking Data
// PURPOSE: Validate required fields, generate booking ID,
//          normalise data, and prepare for downstream nodes.
// ============================================================

const body = $input.first().json.body || $input.first().json;

// ---- Extract fields ----
const name    = (body.name    || '').trim();
const phone   = (body.phone   || '').trim();
const email   = (body.email   || '').trim();
const service = (body.service || '').trim();
const date    = (body.date    || '').trim();
const time    = (body.time    || '').trim();

// ---- Validation helpers ----
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const phoneRegex = /^[\+\d\s\-\(\)]{7,20}$/;
const dateRegex  = /^\d{4}-\d{2}-\d{2}$/;

const errors = [];

if (!name)    errors.push('name is required');
if (!phone)   errors.push('phone is required');
if (!email)   errors.push('email is required');
if (!service) errors.push('service is required');
if (!date)    errors.push('date is required');

if (email  && !emailRegex.test(email))  errors.push('email format is invalid');
if (phone  && !phoneRegex.test(phone))  errors.push('phone format is invalid');
if (date   && !dateRegex.test(date))    errors.push('date must be YYYY-MM-DD format');

if (errors.length > 0) {
  return [{
    json: {
      valid: false,
      errors,
      statusCode: 400,
      message: 'Validation failed: ' + errors.join(', ')
    }
  }];
}

// ---- Generate unique booking ID ----
const ts     = Date.now();
const rand   = Math.floor(1000 + Math.random() * 9000);
const bookingId = `DCL-${ts}-${rand}`;

// ---- Resolve appointment time (default 14:00) ----
const appointmentTime = time || '14:00';

// ---- Build ISO datetime strings for Google Calendar ----
const startISO = `${date}T${appointmentTime}:00`;
const [h, m]   = appointmentTime.split(':').map(Number);
const endMin   = m + 30;
const endH     = h + Math.floor(endMin / 60);
const endISO   = `${date}T${String(endH).padStart(2,'0')}:${String(endMin % 60).padStart(2,'0')}:00`;

// ---- Dublin timezone offset (+00:00 winter / +01:00 summer) ----
// We store local times and let Google Calendar handle TZ via timeZone param.

// ---- Human-readable timestamp for Sheets ----
const now = new Date();
const timestamp = now.toLocaleString('en-IE', { timeZone: 'Europe/Dublin' });

return [{
  json: {
    valid: true,
    bookingId,
    name,
    phone,
    email,
    service,
    date,
    time: appointmentTime,
    timeWasProvided: !!time,
    startISO,
    endISO,
    timestamp,
    rawTimestamp: ts
  }
}];

// Log raw webhook request to Logs sheet payload
const data = $input.first().json;
const now = new Date();
const timestamp = now.toLocaleString('en-IE', { timeZone: 'Europe/Dublin' });

return [{
  json: {
    ...data,
    logTimestamp: timestamp,
    logType: 'INCOMING_REQUEST'
  }
}];

